         public static async Task<ArmOperation<T>> RehydrateAsync<[DynamicallyAccessedMembers(RehydrateMembers)] T>(ArmClient client, RehydrationToken rehydrationToken, ArmClientOptions options = null) where T : notnull
         {

             Argument.AssertNotNull(client, nameof(client));
             Argument.AssertNotNull(rehydrationToken, nameof(rehydrationToken));

             bool isResource = IsResource<T>();
             IOperationSource<T> source = new GenericOperationSource<T>(client, isResource);
